const msg = $input.first().json;
const chatId = String(
  msg.message?.chat?.id ||
  msg.channel_post?.chat?.id ||
  ''
);
const text = (
  msg.message?.text ||
  msg.channel_post?.text ||
  ''
).trim();
const isNew = text.toLowerCase() === '/new';

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const prev = staticData.sessions[chatId];
const prevNum = typeof prev === 'number' && Number.isFinite(prev) ? prev : 0;

if (isNew || prevNum === 0) {
  staticData.sessions[chatId] = prevNum + 1;
}

const sessionNum = staticData.sessions[chatId];
const sessionKey = `chat_${chatId}_s${sessionNum}`;

return [{
  json: {
    chatId,
    text,
    isNew,
    sessionKey
  }
}];

function stripReasoning(text) {
  const parts = text.split(/\n{2,}/);
  if (parts.length <= 1) return text;
  const responseStart = parts.findIndex(p =>
    !p.match(/^(The user|According to|I (should|need|will|must|can)|Let me|Looking at|My |Key |Structure|Since|So I|Wait|Also|But|Actually|Note)/i)
  );
  return responseStart > 0
    ? parts.slice(responseStart).join('\n\n').trim()
    : parts[parts.length - 1].trim();
}

const agentOutput = stripReasoning(
  $input.first().json.response || $input.first().json.text || $input.first().json.output || ''
);
const chatId = $('Extract Context').item.json.chatId;

const xmlMatch = agentOutput.match(/<JobDescription>[\s\S]*?<\/JobDescription>/);
const xmlContent = xmlMatch ? xmlMatch[0] : null;

let jsonContent = null;
const jsonBlockMatch = agentOutput.match(/```json\s*([\s\S]*?)```/);
if (jsonBlockMatch) {
  jsonContent = jsonBlockMatch[1].trim();
} else {
  const bareJsonMatch = agentOutput.match(/(\{[\s\S]*?"id"\s*:\s*"a\d+"[\s\S]*?\})/);
  if (bareJsonMatch) jsonContent = bareJsonMatch[1].trim();
}

let textContent = agentOutput;
if (xmlContent) textContent = textContent.replace(xmlContent, '');
if (jsonBlockMatch) textContent = textContent.replace(jsonBlockMatch[0], '');
else if (jsonContent) textContent = textContent.replace(jsonContent, '');
textContent = textContent.replace(/```json|```/g, '').trim();

return [{
  json: {
    chatId,
    textContent,
    xmlContent,
    jsonContent,
    hasFiles: !!(xmlContent || jsonContent),
    fullOutput: agentOutput
  }
}];

const MAX = 4000;
const fullOutput = $('Parse Output').first().json.fullOutput || '';
const chatId = $('Extract Context').first().json.chatId;

function splitText(text, max) {
  if (!text) return [''];
  if (text.length <= max) return [text];
  const parts = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= max) {
      parts.push(remaining);
      break;
    }
    let sliceEnd = max;
    const lastDouble = remaining.lastIndexOf('\n\n', max);
    const lastSingle = remaining.lastIndexOf('\n', max);
    const lastSpace = remaining.lastIndexOf(' ', max);
    if (lastDouble > max * 0.5) sliceEnd = lastDouble;
    else if (lastSingle > max * 0.5) sliceEnd = lastSingle;
    else if (lastSpace > max * 0.5) sliceEnd = lastSpace;
    parts.push(remaining.slice(0, sliceEnd).trimEnd());
    remaining = remaining.slice(sliceEnd).trimStart();
  }
  return parts;
}

return splitText(fullOutput, MAX).map(chunk => ({
  json: { chatId, chunk }
}));
